-- Compile-time schema snapshot for sqlc. Runtime migrations.go is canonical.
CREATE TABLE records (kind TEXT NOT NULL, key1 TEXT NOT NULL, key2 TEXT NOT NULL DEFAULT '', run_id TEXT NOT NULL DEFAULT '', task_id TEXT NOT NULL DEFAULT '', status TEXT NOT NULL DEFAULT '', created_at INTEGER NOT NULL DEFAULT 0, tool_name TEXT NOT NULL DEFAULT '', idempotency_key TEXT NOT NULL DEFAULT '', data BLOB NOT NULL, PRIMARY KEY(kind,key1,key2));
CREATE INDEX records_kind_run ON records(kind,run_id,created_at,key1);
CREATE INDEX records_kind_task ON records(kind,task_id,created_at,key1);
CREATE UNIQUE INDEX action_attempt_idempotency ON records(kind,run_id,task_id,tool_name,idempotency_key) WHERE kind='action_attempt' AND idempotency_key<>'';
CREATE TABLE events (run_id TEXT NOT NULL, sequence INTEGER NOT NULL, recorded_at INTEGER NOT NULL, data BLOB NOT NULL, PRIMARY KEY(run_id,sequence));
CREATE TABLE leases (id TEXT PRIMARY KEY, run_id TEXT NOT NULL, task_id TEXT NOT NULL, holder_id TEXT NOT NULL, status TEXT NOT NULL, expires_at INTEGER NOT NULL, version INTEGER NOT NULL, data BLOB NOT NULL);
CREATE INDEX leases_task_version ON leases(run_id,task_id,version DESC);
CREATE UNIQUE INDEX leases_active_slot ON leases(run_id,task_id) WHERE status='active';
CREATE TABLE tool_call_charges (run_id TEXT NOT NULL, task_id TEXT NOT NULL, call_id TEXT NOT NULL, tool_name TEXT NOT NULL, input_hash TEXT NOT NULL, created_at INTEGER NOT NULL, PRIMARY KEY(run_id,task_id,call_id));
CREATE INDEX tool_call_charges_run_task ON tool_call_charges(run_id,task_id);
CREATE TABLE sessions (id TEXT PRIMARY KEY, title TEXT NOT NULL DEFAULT '', provider_id TEXT NOT NULL DEFAULT '', model_id TEXT NOT NULL DEFAULT '', reasoning TEXT NOT NULL DEFAULT '', agent_mode TEXT NOT NULL DEFAULT 'single', created_at INTEGER NOT NULL, updated_at INTEGER NOT NULL);
CREATE TABLE session_projections (session_id TEXT PRIMARY KEY REFERENCES sessions(id) ON DELETE CASCADE, last_run_id TEXT NOT NULL DEFAULT '', blocks BLOB NOT NULL DEFAULT '[]', updated_at INTEGER NOT NULL, model_history BLOB NOT NULL DEFAULT '{}', usage BLOB NOT NULL DEFAULT '{}', checkpoint_generation INTEGER NOT NULL DEFAULT 0, cache_epoch INTEGER NOT NULL DEFAULT 0, cache_identity_hash TEXT NOT NULL DEFAULT '');
CREATE TABLE accounts (id TEXT NOT NULL, provider_id TEXT NOT NULL, email TEXT NOT NULL DEFAULT '', display_name TEXT NOT NULL DEFAULT '', plan TEXT NOT NULL DEFAULT '', credential_ref TEXT NOT NULL, status TEXT NOT NULL, created_at INTEGER NOT NULL, updated_at INTEGER NOT NULL, PRIMARY KEY(provider_id,id));
CREATE TABLE auth_credentials (provider_id TEXT NOT NULL, account_id TEXT NOT NULL, data TEXT NOT NULL, created_at INTEGER NOT NULL, updated_at INTEGER NOT NULL, PRIMARY KEY(provider_id,account_id));
CREATE TABLE model_catalog (provider_id TEXT NOT NULL, account_id TEXT NOT NULL, model_id TEXT NOT NULL, etag TEXT NOT NULL DEFAULT '', fetched_at INTEGER NOT NULL, expires_at INTEGER NOT NULL, data BLOB NOT NULL, PRIMARY KEY(provider_id,account_id,model_id));
CREATE TABLE session_todos (session_id TEXT PRIMARY KEY REFERENCES sessions(id) ON DELETE CASCADE, goal TEXT NOT NULL DEFAULT '', revision INTEGER NOT NULL DEFAULT 0, phases BLOB NOT NULL DEFAULT '[]', updated_at INTEGER NOT NULL);
CREATE TABLE memories (memory_rowid INTEGER PRIMARY KEY, id TEXT NOT NULL UNIQUE, content TEXT NOT NULL, anchor TEXT NOT NULL, session_id TEXT NOT NULL DEFAULT '', provenance TEXT NOT NULL, status TEXT NOT NULL, importance INTEGER NOT NULL DEFAULT 0, created_at INTEGER NOT NULL, updated_at INTEGER NOT NULL);
CREATE VIRTUAL TABLE memories_fts USING fts5(content, content='memories', content_rowid='memory_rowid');
CREATE TABLE recaps (session_id TEXT PRIMARY KEY REFERENCES sessions(id) ON DELETE CASCADE, anchor TEXT NOT NULL, covered_boundary TEXT NOT NULL DEFAULT '', revision INTEGER NOT NULL DEFAULT 1, goal TEXT NOT NULL DEFAULT '', summary TEXT NOT NULL DEFAULT '', open_items TEXT NOT NULL DEFAULT '', updated_at INTEGER NOT NULL);
CREATE TABLE context_artifacts (id TEXT PRIMARY KEY, session_id TEXT NOT NULL REFERENCES sessions(id) ON DELETE CASCADE, run_id TEXT NOT NULL DEFAULT '', kind TEXT NOT NULL, sha256 TEXT NOT NULL, payload BLOB NOT NULL, preview TEXT NOT NULL DEFAULT '', created_at INTEGER NOT NULL, UNIQUE(session_id,kind,sha256));
CREATE TABLE session_blocks (session_id TEXT NOT NULL REFERENCES sessions(id) ON DELETE CASCADE, sequence INTEGER NOT NULL, kind TEXT NOT NULL, run_id TEXT NOT NULL DEFAULT '', agent_id TEXT NOT NULL DEFAULT '', data BLOB NOT NULL, PRIMARY KEY(session_id,sequence));
CREATE VIRTUAL TABLE history_fts USING fts5(session_id UNINDEXED, source_type UNINDEXED, source_id UNINDEXED, content);
CREATE TABLE provider_requests (request_id TEXT PRIMARY KEY, provider_request_id TEXT NOT NULL DEFAULT '', session_id TEXT NOT NULL REFERENCES sessions(id) ON DELETE CASCADE, run_id TEXT NOT NULL DEFAULT '', request_kind TEXT NOT NULL, provider TEXT NOT NULL DEFAULT '', model TEXT NOT NULL DEFAULT '', transport TEXT NOT NULL DEFAULT '', cache_epoch INTEGER NOT NULL DEFAULT 0, checkpoint_generation INTEGER NOT NULL DEFAULT 0, input_tokens INTEGER NOT NULL DEFAULT 0, cached_tokens INTEGER NOT NULL DEFAULT 0, cache_write_tokens INTEGER NOT NULL DEFAULT 0, output_tokens INTEGER NOT NULL DEFAULT 0, reasoning_tokens INTEGER NOT NULL DEFAULT 0, total_tokens INTEGER NOT NULL DEFAULT 0, cache_reported INTEGER NOT NULL DEFAULT 0, status TEXT NOT NULL, started_at INTEGER NOT NULL, completed_at INTEGER NOT NULL DEFAULT 0);
CREATE TABLE subagent_runs (id TEXT PRIMARY KEY, session_id TEXT NOT NULL, parent_run_id TEXT NOT NULL, parent_agent_id TEXT NOT NULL DEFAULT '', tool_call_id TEXT NOT NULL DEFAULT '', child_run_id TEXT NOT NULL DEFAULT '', description TEXT NOT NULL DEFAULT '', subagent_type TEXT NOT NULL, state TEXT NOT NULL, summary TEXT NOT NULL DEFAULT '', provider TEXT NOT NULL DEFAULT '', model TEXT NOT NULL DEFAULT '', reasoning TEXT NOT NULL DEFAULT '', capability_mode TEXT NOT NULL DEFAULT '', requested_isolation TEXT NOT NULL DEFAULT 'none', isolation TEXT NOT NULL DEFAULT 'none', cwd TEXT NOT NULL DEFAULT '', background INTEGER NOT NULL DEFAULT 0, output TEXT NOT NULL DEFAULT '', error TEXT NOT NULL DEFAULT '', warning TEXT NOT NULL DEFAULT '', transcript BLOB NOT NULL DEFAULT X'', tool_calls INTEGER NOT NULL DEFAULT 0, turns INTEGER NOT NULL DEFAULT 0, tokens_used INTEGER NOT NULL DEFAULT 0, tools_used BLOB NOT NULL DEFAULT '[]', worktree_path TEXT NOT NULL DEFAULT '', completion_delivered INTEGER NOT NULL DEFAULT 0, started_at INTEGER NOT NULL, finished_at INTEGER NOT NULL DEFAULT 0);
